/**
 * QUICK START GUIDE - DOMAIN AND PRESENTATION LAYER
 * ==================================================
 *
 * This file provides a quick reference for developers integrating the
 * Quantum Messenger Domain and Presentation layers into their Composable screens.
 */

/**
 * FILE LOCATIONS & IMPORTS
 * =========================
 *
 * Domain Layer - Use Cases:
 *   - SendMessageUseCase             → domain/usecase/SendMessageUseCase.kt
 *   - ReceiveMessageUseCase          → domain/usecase/ReceiveMessageUseCase.kt
 *   - GetChatHistoryUseCase          → domain/usecase/GetChatHistoryUseCase.kt
 *   - ReceiveMessageResult (sealed)  → domain/usecase/ReceiveMessageUseCase.kt
 *   - SendMessageException           → domain/usecase/SendMessageUseCase.kt
 *
 * Domain Layer - Models & Repositories:
 *   - ChatMessage (data class)       → domain/model/ChatMessage.kt
 *   - MessageType (enum)             → domain/model/ChatMessage.kt
 *   - ChatRepository (interface)     → domain/repository/ChatRepository.kt
 *
 * Presentation Layer:
 *   - ChatViewModel                  → presentation/viewmodel/ChatViewModel.kt
 *   - ChatUiState (sealed class)     → presentation/viewmodel/ChatUiState.kt
 *
 * DI Modules:
 *   - UseCaseModule                  → domain/di/UseCaseModule.kt
 *   - NetworkModule                  → network/di/NetworkModule.kt
 *
 *
 * BASIC SETUP IN A COMPOSABLE SCREEN
 * ===================================\n *\n * @Composable\n * fun ChatScreen() {\n *   // 1. Get the ViewModel from Hilt\n *   val viewModel: ChatViewModel = hiltViewModel()\n *\n *   // 2. Observe the single state flow\n *   val uiState by viewModel.uiState.collectAsState()\n *\n *   // 3. Initialize ViewModel on first composition\n *   LaunchedEffect(Unit) {\n *     viewModel.initialize(\n *       userId = \"current_user_id\",\n *       participantId = \"recipient_user_id\"\n *     )\n *   }\n *\n *   // 4. Handle all states in a when expression\n *   when (uiState) {\n *     is ChatUiState.Loading -> LoadingUI()\n *     is ChatUiState.Success -> SuccessUI((uiState as ChatUiState.Success), viewModel)\n *     is ChatUiState.Error -> ErrorUI((uiState as ChatUiState.Error), viewModel)\n *   }\n * }\n *\n *\n * HANDLING EACH UI STATE\n * ======================\n *\n * Loading State:\n * --------------- *   @Composable\n *   fun LoadingUI() {\n *     Box(\n *       modifier = Modifier.fillMaxSize(),\n *       contentAlignment = Alignment.Center\n *     ) {\n *       CircularProgressIndicator()\n *       Text(\"Loading messages...\")\n *     }\n *   }\n *\n * Success State:\n * ---------------\n *   @Composable\n *   fun SuccessUI(state: ChatUiState.Success, viewModel: ChatViewModel) {\n *     var inputText by remember { mutableStateOf(\"\") }\n *\n *     Column(modifier = Modifier.fillMaxSize()) {\n *       // Message list\n *       LazyColumn(modifier = Modifier.weight(1f)) {\n *         items(state.messages) { message ->\n *           MessageBubble(\n *             message = message,\n *             isOwn = message.senderId == currentUserId,\n *             onDelete = { viewModel.deleteMessage(message.id) }\n *           )\n *         }\n *       }\n *\n *       // Message input\n *       Row(\n *         modifier = Modifier\n *           .fillMaxWidth()\n *           .padding(8.dp)\n *       ) {\n *         TextField(\n *           value = inputText,\n *           onValueChange = { inputText = it },\n *           modifier = Modifier.weight(1f),\n *           placeholder = { Text(\"Type a message...\") },\n *           enabled = !state.isSending // Disable while sending\n *         )\n *\n *         Button(\n *           onClick = {\n *             if (inputText.isNotBlank()) {\n *               viewModel.sendMessage(inputText)\n *               inputText = \"\" // Clear after sending\n *             }\n *           },\n *           enabled = inputText.isNotBlank() && !state.isSending,\n *           modifier = Modifier.padding(start = 8.dp)\n *         ) {\n *           if (state.isSending) {\n *             CircularProgressIndicator(Modifier.size(20.dp))\n *           } else {\n *             Text(\"Send\")\n *           }\n *         }\n *       }\n *     }\n *   }\n *\n * Error State:\n * -----------\n *   @Composable\n *   fun ErrorUI(state: ChatUiState.Error, viewModel: ChatViewModel) {\n *     Column(\n *       modifier = Modifier.fillMaxSize(),\n *       verticalArrangement = Arrangement.Center,\n *       horizontalAlignment = Alignment.CenterHorizontally\n *     ) {\n *       Icon(\n *         imageVector = Icons.Default.Error,\n *         contentDescription = \"Error\",\n *         modifier = Modifier.size(64.dp),\n *         tint = Color.Red\n *       )\n *       Text(\n *         text = state.message,\n *         fontSize = 16.sp,\n *         textAlign = TextAlign.Center,\n *         modifier = Modifier.padding(16.dp)\n *       )\n *       Button(onClick = { viewModel.retryLoadingMessages() }) {\n *         Text(\"Retry\")\n *       }\n *\n *       // If there are previous messages, show them\n *       if (state.messages.isNotEmpty()) {\n *         Text(\n *           text = \"Showing cached messages\",\n *           fontSize = 12.sp,\n *           color = Color.Gray,\n *           modifier = Modifier.padding(top = 16.dp)\n *         )\n *       }\n *     }\n *   }\n *\n *\n * CORE OPERATIONS\n * ================\n *\n * 1. SENDING A MESSAGE:\n * \n *   viewModel.sendMessage(\"Hello, Alice!\")\n *\n *   What happens:\n *   ✓ Message encrypted via CryptoManager\n *   ✓ Saved to encrypted Room Database\n *   ✓ Converted to Protobuf format\n *   ✓ Sent over WebSocket\n *   ✓ UI shows isSending = true during transmission\n *   ✓ Errors handled gracefully and shown to user\n *\n * 2. RECEIVING MESSAGES:\n *\n *   Automatically happens in ViewModel.observeIncomingMessages()\n *   No explicit call needed\n *\n *   What happens:\n *   ✓ WebSocket emits incoming message\n *   ✓ Protobuf decoded to domain model\n *   ✓ Saved to encrypted database\n *   ✓ Flow automatically emits updated message list\n *   ✓ UI re-composes with new messages\n *\n * 3. MARKING MESSAGE AS READ:\n *\n *   viewModel.markMessageAsRead(messageId)\n *\n *   What happens:\n *   ✓ Database updated with isRead = true\n *   ✓ No UI state change needed\n *   ✓ Errors handled silently\n *\n * 4. DELETING A MESSAGE:\n *\n *   viewModel.deleteMessage(messageId)\n *\n *   What happens:\n *   ✓ Message deleted from database\n *   ✓ Flow emits updated message list\n *   ✓ UI automatically removes the message\n *   ✓ Errors shown as snackbar\n *\n *\n * DEPENDENCY INJECTION SETUP\n * ==========================\n *\n * Ensure your Activity/Application has @HiltAndroidApp:\n *\n *   @HiltAndroidApp\n *   class QuantumMessengerApplication : Application()\n *
 *   // In AndroidManifest.xml:\n *   <application\n *     android:name=\".QuantumMessengerApplication\"\n *     ...\n *   >\n *
 *   // In Activity:\n *   class MainActivity : ComponentActivity() {\n *     override fun onCreate(savedInstanceState: Bundle?) {\n *       super.onCreate(savedInstanceState)\n *       setContent {\n *         ChatScreen() // Hilt will inject ViewModel automatically\n *       }\n *     }\n *   }\n *
 *\n * TESTING COMMON SCENARIOS\n * =========================\n *\n * Test 1: Message Round Trip (Send -> Receive)\n * \n *   // Manual testing flow:\n *   1. Send message: \"Hello in plaintext\"\n *   2. Verify: Message appears encrypted in database\n *   3. Verify: Message transmitted via WebSocket\n *   4. Server receives Protobuf with encrypted payload\n *   5. Server sends back message\n *   6. App observes incoming message\n *   7. Verify: Message decrypted and appears in UI\n *   8. Verify: Database contains encrypted copy\n *\n * Test 2: Error Handling\n *\n *   // Scenario: Network disconnection\n *   1. Kill WebSocket connection\n *   2. Try to send message\n *   3. sendMessage() throws exception\n *   4. ViewModel catches it\n *   5. uiState becomes Error with previous messages\n *   6. User can tap Retry\n *   7. Clean reconnection\n *\n * Test 3: Encryption Verification\n *\n *   // Check database is encrypted:\n *   1. adb shell\n *   2. sqlite3 /data/data/<package>/databases/quantum_messenger.db\n *   3. SELECT content FROM chat_messages;\n *   4. Verify: Content is garbled binary, not readable text\n *\n *\n * DEBUGGING TIPS\n * ==============\n *\n * 1. Check coroutine exceptions:\n *    Add in ViewModel:\n *    viewModelScope.launch {\n *      try { ... } catch (e: Exception) {\n *        Log.e(\"ChatViewModel\", \"Coroutine error\", e)\n *      }\n *    }\n *\n * 2. Monitor StateFlow changes:\n *    val uiState by viewModel.uiState.collectAsState()\n *    Log.d(\"ChatScreen\", \"UI State changed: $uiState\")\n *\n * 3. Verify encryption:\n *    CryptoManager can be tested independently:\n *    val encrypted = runBlocking { cryptoManager.encrypt(\"test\".toByteArray()) }\n *    val decrypted = runBlocking { cryptoManager.decrypt(encrypted) }\n *    assert(String(decrypted) == \"test\")\n *\n * 4. Check WebSocket messages:\n *    Subscribe to WebSocketManager.events:\n *    webSocketManager.events.collect { event ->\n *      Log.d(\"WebSocket\", \"Event: $event\")\n *    }\n *\n *\n * COMMON MISTAKES & FIX\n * ====================\n *\n * Mistake 1: Not calling initialize()\n *   Problem: ViewModel.uiState stays in Loading state\n *   Fix: Call viewModel.initialize(userId, participantId) in LaunchedEffect\n *\n * Mistake 2: Trying to collect StateFlow without .collectAsState()\n *   Problem: Compose doesn't recompose on state changes\n *   Fix: Use \"val state by viewModel.uiState.collectAsState()\"\n *\n * Mistake 3: Sending empty messages\n *   Problem: sendMessage() silently ignores blank strings\n *   Fix: Check inputText.isNotBlank() before calling sendMessage()\n *\n * Mistake 4: Not handling all branches of ChatUiState\n *   Problem: App crashes with \"when is exhaustive\" error\n *   Fix: Add handlers for Loading, Success, AND Error states\n *\n * Mistake 5: Modifying uiState directly\n *   Problem: UI doesn't update because StateFlow is missing\n *   Fix: Use ViewModel methods (sendMessage, deleteMessage) only\n */
